import{_ as a,o as e,c as o,d as h}from"./app-5b49b1a3.js";const s={},i=h('<h1 id="hooks" tabindex="-1"><a class="header-anchor" href="#hooks" aria-hidden="true">#</a> Hooks</h1><h2 id="函数组件和类组件的区别" tabindex="-1"><a class="header-anchor" href="#函数组件和类组件的区别" aria-hidden="true">#</a> 函数组件和类组件的区别</h2><p>1.区别及各自优点</p><ul><li>类组件本质是OOP，继承，属性，内部状态管理。优点：生命周期更齐全，对于当前单个组件功能更齐全</li><li>函数组件本质是FP，输入与输出的映射关系。优点：更纯粹，逻辑复用，易于单元测试，没有类组件的this模糊问题，更好的适应未来的时间分片，并发模式</li></ul><p>2.如何在合适的业务场景下选择</p><ul><li>类组件，在单个复杂组件的生命周期业务逻辑要求更高</li><li>函数组件，通用组件，逻辑复用</li></ul><h2 id="你说学过ahooks库-举例一下印象深刻的" tabindex="-1"><a class="header-anchor" href="#你说学过ahooks库-举例一下印象深刻的" aria-hidden="true">#</a> 你说学过ahooks库，举例一下印象深刻的</h2><h2 id="hooks内部的原理-为什么不能条件表达式中使用" tabindex="-1"><a class="header-anchor" href="#hooks内部的原理-为什么不能条件表达式中使用" aria-hidden="true">#</a> hooks内部的原理（为什么不能条件表达式中使用）</h2>',8),r=[i];function t(d,c){return e(),o("div",null,r)}const n=a(s,[["render",t],["__file","hooks.html.vue"]]);export{n as default};
